jQuery(function($){$('.vh360-giving-amount').on('click',function(){$('[name="amount"]','#vh360-giving-form').val($(this).data('amount'));});$('#vh360-giving-form').on('submit',function(e){e.preventDefault();var $f=$(this),$m=$f.find('.vh360-giving-message');$m.text('Creating secure checkout...');$.post(vh360Giving.ajaxUrl,$f.serialize()+'&action=vh360_giving_create_checkout&nonce='+vh360Giving.nonce).done(function(r){if(r.success&&r.data.checkout_url){window.location=r.data.checkout_url;}else{$m.text((r.data&&r.data.message)||'Unable to start checkout.');}}).fail(function(){$m.text('Unable to start checkout.');});});});
